// One function, many types — TypeScript infers T at each call site
function getFirst<T>(arr: T[]): T | undefined {
  return arr[0];
}

function getLast<T>(arr: T[]): T | undefined {
  return arr[arr.length - 1];
}

const scores = [95, 87, 92, 78, 100];
const names = ["Alice", "Bob", "Carol"];
const dates = ["2024-01-01", "2024-06-15", "2024-12-31"];

// TypeScript infers: getFirst<number>, getFirst<string>
console.log(`Top score: ${getFirst(scores)}`);
console.log(`Last score: ${getLast(scores)}`);
console.log(`First name: ${getFirst(names)}`);
console.log(`Latest date: ${getLast(dates)}`);

interface ApiResponse<T> {
  success: boolean;
  data: T | null;
  error: string | null;
  timestamp: string;
}

function successResponse<T>(data: T): ApiResponse<T> {
  return { success: true, data, error: null, timestamp: new Date().toISOString().slice(0, 10) };
}

function errorResponse<T>(message: string): ApiResponse<T> {
  return { success: false, data: null, error: message, timestamp: new Date().toISOString().slice(0, 10) };
}

interface User { id: number; name: string; }
interface Order { id: string; amount: number; }

const userResult: ApiResponse<User> = successResponse({ id: 1, name: "Alice" });
const orderResult: ApiResponse<Order> = successResponse({ id: "ORD-001", amount: 299 });
const failResult: ApiResponse<User> = errorResponse("User not found");

console.log(`User: ${userResult.data?.name ?? "N/A"}`);
console.log(`Order: $${orderResult.data?.amount ?? 0}`);
console.log(`Error: ${failResult.error}`);

interface HasId {
  id: number;
}

interface HasTimestamps {
  createdAt: string;
  updatedAt: string;
}

// T must have an id — but can have anything else
function findById<T extends HasId>(items: T[], id: number): T | undefined {
  return items.find(item => item.id === id);
}

// T must have timestamps — returns the most recently updated
function getMostRecent<T extends HasTimestamps>(items: T[]): T | undefined {
  return items.reduce((latest, item) =>
    item.updatedAt > latest.updatedAt ? item : latest
  , items[0]);
}

const products = [
  { id: 1, name: "Keyboard",  price: 129, createdAt: "2024-01-01", updatedAt: "2024-03-15" },
  { id: 2, name: "Monitor",   price: 399, createdAt: "2024-01-05", updatedAt: "2024-04-01" },
  { id: 3, name: "Headphones",price: 89,  createdAt: "2024-02-10", updatedAt: "2024-02-10" },
];

const found = findById(products, 2);
console.log(`Found: ${found?.name} — $${found?.price}`);

const recent = getMostRecent(products);
console.log(`Most recently updated: ${recent?.name}`);

function groupBy<T, K extends string | number>(
  items: T[],
  keyFn: (item: T) => K
): Map<K, T[]> {
  const map = new Map<K, T[]>();
  for (const item of items) {
    const key = keyFn(item);
    const group = map.get(key) ?? [];
    group.push(item);
    map.set(key, group);
  }
  return map;
}

const employees = [
  { name: "Alice",  dept: "Engineering", salary: 145000 },
  { name: "Bob",    dept: "Marketing",   salary: 108000 },
  { name: "Carol",  dept: "Engineering", salary: 128000 },
  { name: "Dan",    dept: "HR",          salary: 95000  },
  { name: "Eva",    dept: "Engineering", salary: 138000 },
];

const byDept = groupBy(employees, e => e.dept);

for (const [dept, team] of byDept) {
  const avgSalary = Math.round(team.reduce((s, e) => s + e.salary, 0) / team.length);
  console.log(`${dept}: ${team.length} people, avg $${avgSalary}`);
}
